-- FARM POSITION TAB
local SpotLeft  = Tabs.Spot:AddLeftGroupbox("Positionsüberschreibung ")
local SpotRight = Tabs.Spot:AddRightGroupbox("Schnellspeicher-Taste ")

local overrideLabel = SpotLeft:AddLabel({ Text = "Benutzerdefinierte Position: AUS " })
local savedCFLabel  = SpotLeft:AddLabel({ Text = "Gespeichert: keine " })

SpotLeft:AddButton("Aktuelle Position speichern ", function()
    local char = game.Players.LocalPlayer.Character
    if not char then Library:Notify({Title="Fehler ", Description="Kein Charakter! ", Duration=3}) return end
    local root = char:FindFirstChild("HumanoidRootPart")
    if not root then Library:Notify({Title="Fehler ", Description="Kein HumanoidRootPart! ", Duration=3}) return end
    M.setCustomCFrameOverride(root.CFrame)
    local p = root.Position
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
    Library:Notify({Title="Position gespeichert!", Description=string.format("%.1f, %.1f, %.1f", p.X, p.Y, p.Z), Duration=4})
end)

SpotLeft:AddButton("Benutzerdefinierte Position löschen ", function()
    M.setCustomCFrameOverride(nil)
    savedCFLabel:SetText("Gespeichert: keine ")
    Library:Notify({Title="Gelöscht ", Description="Original erfassten Punkt wird verwendet. ", Duration=3})
end)

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        overrideLabel:SetText("Custom Position: " .. (M.getCustomCFrameOverride() and "ON " or "OFF "))
    end
end)

