end)

SpotRight:AddButton("Schnellspeicher-Taste löschen ", function()
    M.setTeleportKeybind(nil)
    keybindLabel:SetText("Schnellspeicher-Taste: keine ")
    Library:Notify({Title="Taste gelöscht ", Description="Keine Schnellspeicher-Taste festgelegt. ", Duration=3})
end)

M.onKeybindSet = function(keyCode)
